                                     opt->results(), arraySeparator, arrayStart, arrayEnd, stringQuote, literalQuote);
                             }
                         }
+                        // If get_flag_value() returned a custom (non-boolean) string that contains
+                        // config-special characters (delimiter, comment char, or array start),
+                        // pass it through convert_arg_for_ini() to ensure proper quoting.
+                        if(value != "true" && value != "false" && !value.empty() &&
+                           value.front() != stringQuote && value.front() != literalQuote) {
+                            const std::string specialChars =
+                                std::string(1, commentChar) + valueDelimiter + arrayStart;
+                            if(value.find_first_of(specialChars) != std::string::npos) {
+                                value = detail::convert_arg_for_ini(value, stringQuote, literalQuote, true);
+                            }
+                        }
